    "content": "import OpensidianPlugin from '../../main';
import { OpenCodeConfig, OpenCodeAuth, ProviderConfig } from '../types/opencode';
import { StreamChunk, QueryOptions, ImageAttachment } from '../types/chat';
import { FREE_MODELS, ZEN_MODELS, ModelInfo, getModelEndpoint } from '../types/settings';
import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import { exec, spawn } from 'child_process';
import { promisify } from 'util';
import * as readline from 'readline';

const execAsync = promisify(exec);

interface OpenCodeProvider {
  id: string;
  config: ProviderConfig;
  apiKey?: string;
  baseURL?: string;
}

interface OpenCodeSession {
  id: string;
  title?: string;
  messages: any[];
  createdAt: number;
  updatedAt: number;
}

export class OpenCodeService {
  private plugin: OpensidianPlugin;
  private opencodeConfig: OpenCodeConfig | null = null;
  private opencodeAuth: OpenCodeAuth | null = null;
  private activeProvider: OpenCodeProvider | null = null;
  private isInitialized = false;
  private abortController: AbortController | null = null;
  private currentSessionId: string | null = null;
  private availableModels: ModelInfo[] = [];
  private opencodePath: string | null = null;
  private availableMCPServers: Array<{name: string; description?: string; enabled: boolean}> = [];
  private availableSkills: Array<{name: string; description?: string; enabled: boolean}> = [];
  constructor(plugin: OpensidianPlugin) {
    this.plugin = plugin;
  }

  isReady(): boolean {
    return this.isInitialized;
  }

  /**
   * 重置服务状态，允许重新初始化
   */
  reset(): void {
    this.isInitialized = false;
    this.opencodePath = null;
    this.availableModels = [];
    this.activeProvider = null;
    this.opencodeConfig = null;
    this.opencodeAuth = null;
    console.log('OpenCode service reset');
  }

  async initialize(): Promise<void> {
    if (this.isInitialized) return;

    // Find OpenCode CLI path
    await this.findOpenCodePath();

    // Load opencode configuration
    if (this.plugin.settings.autoLoadOpencodeConfig) {
      await this.loadOpencodeConfig();
    }

    // Setup active provider
    await this.setupProvider();

    // Load available models
    await this.loadAvailableModels();

    // Load available MCP servers and skills
    await this.loadAvailableMCPServers();
    await this.loadAvailableSkills();

    this.isInitialized = true;
    console.log('OpenCode service initialized');
  }

  private getTempDir(): string {
    // 优先使用用户配置的临时目录，避免特殊字符路径问题
    if (this.plugin.settings.tempDir && this.plugin.settings.tempDir.trim()) {
      const customDir = this.plugin.settings.tempDir.trim();
      console.log('Using custom temporary directory:', customDir);
      return customDir;
    }
    const systemTempDir = os.tmpdir();
    console.log('Using system temporary directory:', systemTempDir);
    return systemTempDir;
  }

  private async safeUnlink(filePath: string): Promise<void> {
    if (!fs.existsSync(filePath)) {
      console.log('File does not exist, skipping cleanup:', filePath);
      return;
    }

    // 尝试多次删除，处理 EBUSY 错误
    const maxRetries = 5;
    const retryDelay = 1000; // 1秒

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        fs.unlinkSync(filePath);
        console.log('Successfully cleaned up temporary file:', filePath);
        return;
      } catch (error: any) {
        if (error.code === 'EBUSY' && attempt < maxRetries) {
          console.warn(`File ${filePath} is busy, retrying (${attempt}/${maxRetries})...`);
          // 等待一段时间后重试，使用异步延迟避免阻塞
          await new Promise(resolve => setTimeout(resolve, retryDelay));
        } else {
          console.warn(`Failed to cleanup temporary file after ${attempt} attempts:`, filePath, error);
          // 如果仍然失败，尝试重命名文件（避免积累临时文件）
          try {
            const newPath = filePath + '.deleted';
            fs.renameSync(filePath, newPath);
            console.log('Renamed busy file to:', newPath);
          } catch (renameError) {
            console.warn('Failed to rename busy file:', renameError);
          }
          break;
        }
      }
    }
  }

  public async findOpenCodePath(): Promise<void> {
    // Use configured path first
    if (this.plugin.settings.opencodePath) {
      this.opencodePath = this.plugin.settings.opencodePath.replace(/\r/g, '').trim();
      return;
    }

    // Try using PATH first (fast and reliable)
    try {
      const cmd = process.platform === 'win32' ? 'where opencode' : 'which opencode';
      const { stdout } = await execAsync(cmd);
      const foundPath = stdout.trim().split('\n')[0]?.replace(/["\r\n]+/g, '').trim();
      if (foundPath) {
        this.opencodePath = foundPath;
        console.log('Found opencode via PATH:', foundPath);
        return;
      }
    } catch {
      console.warn('OpenCode CLI not found in PATH');
    }

    // Try to find opencode in common locations
    const possiblePaths: string[] = [];
    const appData = process.env.APPDATA;
    const localAppData = process.env.LOCALAPPDATA;
    const programFiles = process.env.ProgramFiles;
    const programFilesX86 = process.env['ProgramFiles(x86)'];

    if (process.platform === 'win32') {
      if (appData) {
        possiblePaths.push(
          path.join(appData, 'npm', 'opencode.cmd'),
          path.join(appData, 'npm', 'opencode')
        );
      }
      if (localAppData) {
        possiblePaths.push(
          path.join(localAppData, 'Programs', 'nodejs', 'opencode.cmd'),
          path.join(localAppData, 'Programs', 'nodejs', 'opencode')
        );
      }
      if (programFiles) {
        possiblePaths.push(
          path.join(programFiles, 'nodejs', 'opencode.cmd'),
          path.join(programFiles, 'nodejs', 'opencode')
        );
      }
      if (programFilesX86) {
        possiblePaths.push(
          path.join(programFilesX86, 'nodejs', 'opencode.cmd'),
          path.join(programFilesX86, 'nodejs', 'opencode')
        );
      }
      possiblePaths.push(
        path.join(process.cwd(), 'opencode.cmd'),
        path.join(process.cwd(), 'opencode')
      );
    } else {
      possiblePaths.push(
        '/usr/local/bin/opencode',
        '/usr/bin/opencode',
        path.join(process.cwd(), 'opencode')
      );
    }

    for (const p of possiblePaths) {
      try {
        if (fs.existsSync(p)) {
          this.opencodePath = p;
          console.log('Found opencode at:', p);
          return;
        }
      } catch {
        // Continue trying
      }
    }

  }

  private async loadOpencodeConfig(): Promise<void> {
    try {
      // 1. Try vault-specific config first
      const vaultConfig = await this.plugin.storage.loadOpencodeConfig();
      if (vaultConfig) {
        console.log('Loaded opencode config from vault');
      }

      // 2. Try global config
      let globalConfig: OpenCodeConfig | null = null;
      const customPath = this.plugin.settings.opencodeConfigPath;
      const globalConfigPath = customPath || this.getGlobalConfigPath();
      if (globalConfigPath && fs.existsSync(globalConfigPath)) {
        const content = fs.readFileSync(globalConfigPath, 'utf-8');
        globalConfig = this.parseJsonWithComments(content);
        console.log('Loaded opencode config from global');
      }

      if (globalConfig && vaultConfig) {
        this.opencodeConfig = this.mergeConfigs(globalConfig, vaultConfig);
      } else {
        this.opencodeConfig = vaultConfig || globalConfig;
      }

      // 3. Try to load auth info (always)
      await this.loadAuthConfig();
    } catch (error) {
      console.error('Failed to load opencode config:', error);
    }
  }

  private async loadAuthConfig(): Promise<void> {
    try {
      const authPath = this.getAuthPath();
      if (authPath && fs.existsSync(authPath)) {
        const content = fs.readFileSync(authPath, 'utf-8');
        this.opencodeAuth = JSON.parse(content);
        console.log('Loaded opencode auth');
      }
    } catch (error) {
      console.error('Failed to load auth config:', error);
    }
  }

  private getGlobalConfigPath(): string | null {
    const homeDir = process.env.HOME || process.env.USERPROFILE;
    if (!homeDir) return null;
    const appData = process.env.APPDATA;
    const localAppData = process.env.LOCALAPPDATA;
    const locations = [
      path.join(homeDir, '.config', 'opencode', 'opencode.json'),
      appData ? path.join(appData, 'opencode', 'opencode.json') : null,
      localAppData ? path.join(localAppData, 'opencode', 'opencode.json') : null,
    ].filter(Boolean) as string[];

    for (const loc of locations) {
      if (fs.existsSync(loc)) return loc;
    }
    return locations[0] || null;
  }

  private getAuthPath(): string | null {
    const homeDir = process.env.HOME || process.env.USERPROFILE;
    if (!homeDir) return null;

    const appData = process.env.APPDATA;
    const localAppData = process.env.LOCALAPPDATA;
    const locations = [
      path.join(homeDir, '.local', 'share', 'opencode', 'auth.json'),
      path.join(homeDir, '.config', 'opencode', 'auth.json'),
      appData ? path.join(appData, 'opencode', 'auth.json') : null,
      localAppData ? path.join(localAppData, 'opencode', 'auth.json') : null,
    ];

    for (const loc of locations) {
      if (fs.existsSync(loc)) return loc;
    }
    return null;
  }

  private getSessionsPath(): string | null {
    const homeDir = process.env.HOME || process.env.USERPROFILE;
    if (!homeDir) return null;
    const appData = process.env.APPDATA;
    const localAppData = process.env.LOCALAPPDATA;
    const locations = [
      path.join(homeDir, '.local', 'share', 'opencode', 'sessions'),
      path.join(homeDir, '.config', 'opencode', 'sessions'),
      appData ? path.join(appData, 'opencode', 'sessions') : null,
      localAppData ? path.join(localAppData, 'opencode', 'sessions') : null,
    ].filter(Boolean) as string[];

    for (const loc of locations) {
      if (fs.existsSync(loc)) return loc;
    }
    return locations[0] || null;
  }

  private parseJsonWithComments(content: string): any {
    const stripped = this.stripJsonComments(content);
    return JSON.parse(stripped);
  }

  private stripJsonComments(input: string): string {
    let output = '';
    let inString = false;
    let stringChar = '';
    let inLineComment = false;
    let inBlockComment = false;
    let escape = false;

    for (let i = 0; i < input.length; i++) {
      const char = input[i];
      const next = i + 1 < input.length ? input[i + 1] : '';

      if (inLineComment) {
        if (char === '\n') {
          inLineComment = false;
          output += char;
        }
        continue;
      }

      if (inBlockComment) {
        if (char === '*' && next === '/') {
          inBlockComment = false;
          i++;
        }
        continue;
      }

      if (inString) {
        output += char;
        if (escape) {
          escape = false;
        } else if (char === '\\') {
          escape = true;
        } else if (char === stringChar) {
          inString = false;
          stringChar = '';
        }
        continue;
      }

      if (char === '"' || char === "'") {
        inString = true;
        stringChar = char;
        output += char;
        continue;
      }

      if (char === '/' && next === '/') {
        inLineComment = true;
        i++;
        continue;
      }

      if (char === '/' && next === '*') {
        inBlockComment = true;
        i++;
        continue;
      }

      output += char;
    }

    return output;
  }

  private mergeConfigs(base: any, override: any): any {
    if (!base) return override;
    if (!override) return base;
    if (Array.isArray(base) || Array.isArray(override)) {
      return override ?? base;
    }
    if (typeof base !== 'object' || typeof override !== 'object') {
      return override;
    }
    const result: any = { ...base };
    for (const [key, value] of Object.entries(override)) {
      if (value && typeof value === 'object' && !Array.isArray(value)) {
        result[key] = this.mergeConfigs((base as any)[key], value);
      } else {
        result[key] = value;
      }
    }
    return result;
  }

  private async setupProvider(): Promise<void> {
    // 如果使用本地模型，跳过 OpenCode 配置
    if (this.plugin.settings.localModel.enabled) {
      console.log('Using local model, skipping OpenCode provider setup');
      return;
    }

    const modelId = this.plugin.settings.model === 'auto' 
      ? this.getDefaultModel() 
      : this.plugin.settings.model;

    if (!modelId) {
      console.warn('No model configured');
      return;
    }

    const [providerId, modelName] = modelId.includes('/') 
      ? modelId.split('/') 
      : [modelId, 'default'];

    console.log(`Setting up provider for model: ${modelId}, provider: ${providerId}`);

    // 检查是否为免费模型或OpenCode Zen模型
    const isFreeModel = modelId.startsWith('opencode/');
    const isZenModel = modelId.startsWith('opencode/') && !modelId.includes('free');

    if (isFreeModel || isZenModel) {
      console.log(`Using ${isFreeModel ? 'free' : 'Zen'} model: ${modelId}, no provider config needed`);
      this.activeProvider = {
        id: 'opencode',
        config: { type: 'opencode' } as ProviderConfig,
        apiKey: this.plugin.settings.opencodeZenApiKey || this.opencodeAuth?.['opencode']?.apiKey,
        baseURL: 'https://opencode.ai/zen/v1',
      };
      return;
    }

    // 检查是否为deepseek模型（通过OpenCode Zen提供）
    if (providerId === 'deepseek') {
      console.log(`Using deepseek model via OpenCode Zen: ${modelId}`);
      this.activeProvider = {
        id: 'opencode',
        config: { type: 'opencode' } as ProviderConfig,
        apiKey: this.plugin.settings.opencodeZenApiKey || this.opencodeAuth?.['opencode']?.apiKey,
        baseURL: 'https://opencode.ai/zen/v1',
      };
      return;
    }

    // 如果使用免费模型且没有配置
    if (this.plugin.settings.useFreeModels && !this.opencodeConfig) {
      console.log('Using free models without OpenCode config');
      return;
    }

    if (!this.opencodeConfig) {
      console.warn('No opencode config found');
      return;
    }

    const providerConfig = this.opencodeConfig.provider?.[providerId];
    if (!providerConfig) {
      console.warn(`Provider ${providerId} not found in config, using OpenCode Zen as fallback`);
      this.activeProvider = {
        id: 'opencode',
        config: { type: 'opencode' } as ProviderConfig,
        apiKey: this.plugin.settings.opencodeZenApiKey || this.opencodeAuth?.['opencode']?.apiKey,
        baseURL: 'https://opencode.ai/zen/v1',
      };
      return;
    }

    const apiKey = this.opencodeAuth?.[providerId]?.apiKey 
      || providerConfig.options?.apiKey;

    this.activeProvider = {
      id: providerId,
      config: providerConfig,
      apiKey,
      baseURL: providerConfig.options?.baseURL,
    };

    console.log(`Provider ${providerId} configured with model ${modelName}`);
  }

  private getDefaultModel(): string {
    // 优先使用免费模型
    if (this.plugin.settings.useFreeModels) {
      return 'opencode/big-pickle';
    }

    // 使用OpenCode配置中的模型
    if (this.opencodeConfig?.model) {
      return this.opencodeConfig.model;
    }

    // 默认使用免费模型
    return 'opencode/big-pickle';
  }

  async loadAvailableModels(): Promise<ModelInfo[]> {
    this.availableModels = [];

    // 1. Add free models
    this.availableModels.push(...FREE_MODELS);

    // 2. Add Zen models if user has API key
    if (this.plugin.settings.opencodeZenApiKey || this.opencodeAuth?.['opencode']) {
      this.availableModels.push(...ZEN_MODELS);
    }

    // 3. Add models from OpenCode config (if available)
    const configModels = this.getModelsFromConfig();
    for (const model of configModels) {
      if (!this.availableModels.find(m => m.id === model.id)) {
        this.availableModels.push(model);
      }
    }

    // 4. Try to load models from OpenCode CLI
    if (this.opencodePath) {
      try {
        const cliModels = await this.getModelsFromCLI();
        for (const model of cliModels) {
          if (!this.availableModels.find(m => m.id === model.id)) {
            this.availableModels.push(model);
          }
        }
      } catch (error) {
        console.warn('Failed to load models from CLI:', error);
      }
    }

    // 5. Add local models if enabled
    if (this.plugin.settings.localModel.enabled) {
      this.availableModels.push({
        id: `local/${this.plugin.settings.localModel.model}`,
        name: `Local: ${this.plugin.settings.localModel.model}`,
        provider: 'local',
      });
    }

    console.log(`Loaded ${this.availableModels.length} available models`);
    return this.availableModels;
  }

  private async getModelsFromCLI(): Promise<ModelInfo[]> {
    if (!this.opencodePath) return [];

    try {
      const isWindows = process.platform === 'win32';
      const commands = isWindows ? [
        `"${this.opencodePath}" models --format json 2>NUL`,
        `"${this.opencodePath}" models 2>NUL`
      ] : [
        `"${this.opencodePath}" models --format json 2>/dev/null`,
        `"${this.opencodePath}" models 2>/dev/null`
      ];

      let output = '';
      for (const cmd of commands) {
        try {
          const result = await execAsync(cmd, { 
            maxBuffer: 10 * 1024 * 1024,
            timeout: this.plugin.settings.cliTimeout || 300000,
            cwd: this.getCliCwd(),
          });
          output = result.stdout || result.stderr || '';
          if (output.trim()) break;
        } catch {
          continue;
        }
      }

      if (!output) {
        return [];
      }

      // Try to parse as JSON first
      try {
        const models = JSON.parse(output);
        const list = Array.isArray(models)
          ? models
          : Array.isArray(models?.data)
            ? models.data
            : Array.isArray(models?.models)
              ? models.models
              : [];

        if (Array.isArray(list) && list.length > 0) {
          const models: ModelInfo[] = [];
          for (const m of list) {
            const rawId = m.id || (m.provider && m.name ? `${m.provider}/${m.name}` : m.name);
            if (!rawId) continue;
            const provider = m.provider || rawId.split('/')[0] || 'unknown';
            models.push({
              id: rawId,
              name: m.name || m.id || rawId,
              provider: provider || 'unknown',
            });
          }
          return models;
        }
      } catch {
        // Parse text output
        const lines = output.trim().split('\n');
        const models: ModelInfo[] = [];
        for (const line of lines) {
          const match = line.match(/(\S+\/\S+)/);
          if (match) {
            models.push({
              id: match[1],
              name: match[1],
              provider: match[1].split('/')[0],
            });
          }
        }
        return models;
      }
    } catch (error) {
      console.warn('Failed to get models from CLI:', error);
    }

    return [];
  }

  private getModelsFromConfig(): ModelInfo[] {
    const models: ModelInfo[] = [];
    if (!this.opencodeConfig) return models;

    const providers = this.opencodeConfig.provider || {};
    const modelIds = new Set<string>();
    if (this.opencodeConfig.model) modelIds.add(this.opencodeConfig.model);
    if (this.opencodeConfig.small_model) modelIds.add(this.opencodeConfig.small_model);

    for (const id of modelIds) {
      if (!id) continue;
      let normalizedId = id;
      let provider = 'unknown';
      let name = id;

      if (id.includes('/')) {
        const parts = id.split('/');
        provider = parts[0] || 'unknown';
        name = parts[1] || id;
      } else {
        for (const [providerId, providerConfig] of Object.entries(providers)) {
          if (providerConfig?.models && providerConfig.models[id]) {
            normalizedId = `${providerId}/${id}`;
            provider = providerId || 'unknown';
            name = providerConfig.models[id]?.name || id;
            break;
          }
        }
      }

      models.push({
        id: normalizedId,
        name,
        provider,
      });
    }

    for (const [providerId, providerConfig] of Object.entries(providers)) {
      const providerModels = providerConfig?.models || {};
      for (const [modelKey, modelConfig] of Object.entries(providerModels)) {
        const rawId = modelConfig?.id || modelKey;
        const fullId = rawId.includes('/') ? rawId : `${providerId}/${rawId}`;
        models.push({
          id: fullId,
          name: modelConfig?.name || rawId,
          provider: providerId || 'unknown',
        });
      }
    }

    return models;
  }

  getAvailableModels(): ModelInfo[] {
    return this.availableModels;
  }

  getAvailableMCPServers(): Array<{name: string; description?: string; enabled: boolean}> {
    return this.availableMCPServers;
  }

  getAvailableSkills(): Array<{name: string; description?: string; enabled: boolean}> {
    return this.availableSkills;
  }

  getActiveModel(): string {
    // 优先使用本地模型
    if (this.plugin.settings.localModel.enabled) {
      return `local/${this.plugin.settings.localModel.model}`;
    }

    // 使用免费模型
    if (this.plugin.settings.useFreeModels && !this.opencodeConfig) {
      return FREE_MODELS[0].id;
    }

    if (this.plugin.settings.model !== 'auto') {
      return this.plugin.settings.model;
    }
    return this.opencodeConfig?.model || FREE_MODELS[0].id;
  }

  getActiveProviderId(): string | null {
    if (this.plugin.settings.localModel.enabled) {
      return 'local';
    }
    return this.activeProvider?.id || 'opencode';
  }

  hasValidConfig(): boolean {
    return this.activeProvider !== null || 
           this.plugin.settings.localModel.enabled ||
           (this.plugin.settings.useFreeModels && !this.opencodeConfig);
  }

  async switchModel(modelId: string): Promise<void> {
    this.plugin.settings.model = modelId;
    await this.plugin.saveSettings();

    // 重新设置 provider
    if (!modelId.startsWith('local/')) {
      await this.setupProvider();
    }
  }

  async *query(
    prompt: string, 
    options?: QueryOptions
  ): AsyncGenerator<StreamChunk> {
    if (!this.isReady()) {
      yield {
        type: 'error',
        error: 'OpenCode service not initialized'
      };
      return;
    }

    // 取消之前的请求
    if (this.abortController) {
      this.abortController.abort();
    }
    this.abortController = new AbortController();

    try {
      // 检查是否禁用了API回退
      const disableApiFallback = this.plugin.settings.disableApiFallback;

      // CLI 是否可用
      const cliAvailable = this.opencodePath && !this.plugin.settings.localModel.enabled;

      if (disableApiFallback) {
        // 如果禁用了API回退，必须使用CLI
        if (!cliAvailable) {
          throw new Error('API fallback is disabled but CLI is not available. ' +
            'Please configure OpenCode CLI path or enable local model.');
        }

        // 只使用CLI，失败时不回退
        yield* this.queryViaCLI(prompt, options);
        return;
      } else {
        // 默认逻辑：优先使用CLI，失败时回退到API
        if (cliAvailable) {
          try {
            yield* this.queryViaCLI(prompt, options);
            return;
          } catch (cliError) {
            console.warn('CLI query failed, falling back to API:', cliError);
          }
        }

        // 回退到 API 请求
        yield* this.queryViaAPI(prompt, options);
      }
    } catch (error) {
      if (error instanceof Error && error.name === 'AbortError') {
        yield { type: 'error', error: 'Request cancelled' };
      } else {
        console.error('Query error:', error);
        yield {
          type: 'error',
          error: error instanceof Error ? error.message : 'Unknown error'
        };
      }
    } finally {
      this.abortController = null;
    }
  }

  private async *queryViaCLI(
    prompt: string,
    options?: QueryOptions
  ): AsyncGenerator<StreamChunk> {
    // 多级调用降级策略：依次尝试不同的 CLI 调用方式
    const methods = [
      this.queryViaCLISpawn.bind(this),
      this.queryViaCLIPipe.bind(this),
      this.queryViaCLIRedirect.bind(this),
    ];

    const methodNames = ['spawn', 'pipe', 'redirect'];
    let lastError: Error | null = null;

    for (let i = 0; i < methods.length; i++) {
      const method = methods[i];
      const methodName = methodNames[i];

      console.log(`Trying CLI method ${i+1}/${methods.length}: ${methodName}`);

      try {
        yield* method(prompt, options);
        console.log(`CLI method ${methodName} succeeded`);
        return;
      } catch (error) {
        console.error(`CLI method ${methodName} failed:`, error);
        lastError = error instanceof Error ? error : new Error(String(error));

        // 如果不是最后一个方法，继续尝试下一个
        if (i < methods.length - 1) {
          console.log(`Falling back to next method...`);
          // 等待短暂时间，避免快速重试
          await new Promise(resolve => setTimeout(resolve, 100));
        }
      }
    }

    // 所有方法都失败了
    console.error('All CLI methods failed');
    throw lastError || new Error('All CLI methods failed');
  }

  private buildCLIArgs(options?: QueryOptions): string[] {
    const model = options?.model || this.getActiveModel();
    const temperature = options?.temperature ?? 0.7;

    const args = ['run', '--format', 'json', '-m', model];
    if (temperature !== 0.7) {
      args.push('--temperature', temperature.toString());
    }
    if (options?.maxTokens) {
      args.push('--max-tokens', options.maxTokens.toString());
    }
    if (options?.thinking) {
      args.push('--thinking');
    }

    console.log('CLI args:', args, 'thinking:', options?.thinking);
    return args;
  }

  private parseCLIResponse(stdout: string): {text: string, thinking: string} {
    console.log('CLI raw response (first 500 chars):', stdout.substring(0, 500));

    try {
      const lines = stdout.trim().split('\n');
      let textContent = '';
      let thinkingContent = '';
      let hasError = false;
      let errorMessage = '';

      for (const line of lines) {
        if (!line.trim()) continue;

        try {
          const event = JSON.parse(line.trim());

          // 处理错误事件
          if (event.type === 'error') {
            hasError = true;
            errorMessage = event.error?.message || event.error || 'CLI error';
            console.error('CLI error event:', event);
            break;
          }

          // 处理思考事件
          if (event.type === 'reasoning' && event.part?.text) {
            thinkingContent += event.part.text;
          }

          // 处理文本事件
          if (event.type === 'text' && event.part?.text) {
            textContent += event.part.text;
          }

          // 也可以从其他字段提取文本
          if (!textContent && event.text) {
            textContent = event.text;
          }
          if (!textContent && event.content) {
            textContent = event.content;
          }
          if (!textContent && event.message) {
            textContent = event.message;
          }
          if (!textContent && event.part?.text) {
            textContent = event.part.text;
          }

        } catch (lineParseError) {
          console.warn('Failed to parse CLI response line:', line, lineParseError);
          // 继续处理其他行
        }
      }

      if (hasError) {
        throw new Error(errorMessage);
      }

      if (!textContent) {
        console.warn('Could not extract text from CLI response. Raw output:', stdout);
        // 尝试将整个输出作为文本
        textContent = stdout.trim();
      }

      console.log('Extracted text content (first 200 chars):', textContent.substring(0, 200));
      if (thinkingContent) {
        console.log('Extracted thinking content (first 200 chars):', thinkingContent.substring(0, 200));
      }
      return {text: textContent, thinking: thinkingContent};

    } catch (parseError) {
      console.error('Failed to parse CLI response:', parseError);
      console.error('Raw stdout:', stdout);

      // 如果 JSON 解析失败，尝试直接使用 stdout 作为文本
      if (stdout.trim()) {
        return {text: stdout.trim(), thinking: ''};
      } else {
        throw parseError instanceof Error ? parseError : new Error('Invalid CLI response');
      }
    }
  }

  private async *processCLIStream(stream: NodeJS.ReadableStream): AsyncGenerator<StreamChunk> {
    const rl = readline.createInterface({
      input: stream,
      crlfDelay: Infinity
    });

    for await (const line of rl) {
      if (!line.trim()) continue;

      try {
        const event = JSON.parse(line.trim());

        // 处理错误事件
        if (event.type === 'error') {
          console.error('CLI error event:', event);
          yield {
            type: 'error',
            error: event.error?.message || event.error || 'CLI error'
          };
          return;
        }

        // 处理思考事件
        if (event.type === 'reasoning' && event.part?.text !== undefined) {
          yield {
            type: 'thinking',
            content: event.part.text
          };
        }

        // 处理文本事件
        if (event.type === 'text' && event.part?.text !== undefined) {
          yield {
            type: 'text',
            content: event.part.text
          };
        }

        // 处理其他文本字段（兼容性）
        if (event.type === 'text' && event.text !== undefined) {
          yield {
            type: 'text',
            content: event.text
          };
        }

        // 处理步骤完成事件（忽略，继续）
        if (event.type === 'step_finish') {
          // 步骤完成，继续等待更多内容
        }

      } catch (parseError) {
        console.warn('Failed to parse CLI response line:', line, parseError);
        // 继续处理其他行
      }
    }

    yield { type: 'done' };
  }

  private async *queryViaCLISpawn(
    prompt: string,
    options?: QueryOptions
  ): AsyncGenerator<StreamChunk> {
    if (!this.opencodePath) {
      throw new Error('OpenCode CLI not available');
    }

    // 构建完整的消息，包含系统提示和对话历史
    const messages = this.buildMessages(prompt, options);
    const model = options?.model || this.getActiveModel();
    const temperature = options?.temperature ?? 0.7;
    const maxTokens = options?.maxTokens;

    // 创建临时文件存储请求数据
    const tempDir = this.getTempDir();
    const tempFile = path.join(tempDir, `opencode-request-${Date.now()}.json`);
    let tempFileCreated = false;

    try {
      // 构建请求数据
      const requestData = {
        messages,
        model,
        temperature,
        max_tokens: maxTokens,
        stream: true // 启用流式响应
      };

      console.log('Request data:', JSON.stringify(requestData, null, 2));

      // 写入临时文件
      fs.writeFileSync(tempFile, JSON.stringify(requestData, null, 2));
      tempFileCreated = true;
      console.log('Created temporary request file:', tempFile);

      // 读取文件内容
      const requestContent = fs.readFileSync(tempFile, 'utf-8');

      // 构建命令参数
      const args = this.buildCLIArgs(options);

      console.log('Spawning opencode with args:', args);
      console.log('Opencode path:', this.opencodePath);

      // 使用 spawn 而不是 exec，避免 shell 处理路径中的特殊字符
      const child = spawn(`"${this.opencodePath}"`, args, {
        shell: true, // 使用 shell 以处理路径中的空格和引号
        windowsHide: true,
        stdio: ['pipe', 'pipe', 'pipe']
      });

      // 设置超时
      const timeout = this.plugin.settings.cliTimeout || 300000; // 使用配置的超时时间，默认 300 秒
      const timeoutId = setTimeout(() => {
        try {
          child.kill('SIGTERM');
        } catch (e) {
          console.warn('Failed to kill child process on timeout:', e);
        }
      }, timeout);

      // 写入请求内容到 stdin
      child.stdin.write(requestContent);
      child.stdin.end();

      // 收集 stderr 用于错误报告
      let stderr = '';
      child.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      // 创建 readline 接口用于逐行处理 stdout
      const rl = readline.createInterface({
        input: child.stdout,
        crlfDelay: Infinity
      });

      // 创建进程退出 promise
      const exitPromise = new Promise<number | null>((resolve, reject) => {
        child.on('error', reject);

        child.on('close', (code, _signal) => {
          clearTimeout(timeoutId);
          resolve(code);
        });
      });

      // 工具调用计数器和循环保护
      const MAX_TOOL_CALLS = 50; // 最大工具调用次数
      const MAX_STEP_START = 100; // 最大 step_start 事件数
      let toolCallCount = 0;
      let stepStartCount = 0;

      // 实时逐行处理 stdout 流
      try {
        for await (const line of rl) {
          if (!line.trim()) continue;

          try {
            const event = JSON.parse(line.trim());

            // 处理错误事件
            if (event.type === 'error') {
              console.error('CLI error event:', event);
              yield {
                type: 'error',
                error: event.error?.message || event.error || 'CLI error'
              };
              return;
            }

            // 处理思考事件
            if (event.type === 'reasoning' && event.part?.text !== undefined) {
              yield {
                type: 'thinking',
                content: event.part.text
              };
            }

            // 处理文本事件
            if (event.type === 'text' && event.part?.text !== undefined) {
              yield {
                type: 'text',
                content: event.part.text
              };
            }

            // 处理其他文本字段（兼容性）
            if (event.type === 'text' && event.text !== undefined) {
              yield {
                type: 'text',
                content: event.text
              };
            }

            // 处理 step_start 事件 - 检测无限循环
            if (event.type === 'step_start' || event.type === 'step-start') {
              stepStartCount++;
              console.log(`[OpenCode] step_start #${stepStartCount}`, event.part?.id || '');

              // 检查是否超过最大 step_start 数量
              if (stepStartCount > MAX_STEP_START) {
                console.error(`Too many step_start events (${stepStartCount}), possible infinite loop detected`);
                yield {
                  type: 'error',
                  error: `检测到可能的无限循环 (step_start: ${stepStartCount})，已自动终止`
                };
                return;
              }
              continue; // 继续等待后续事件
            }

            // 处理步骤完成事件（忽略，继续）
            if (event.type === 'step_finish' || event.type === 'step-finish') {
              // 步骤完成，继续等待更多内容
              continue;
            }

            // 记录其他事件类型以便调试
            if (event.type !== 'text' && event.type !== 'reasoning' && event.type !== 'error') {
              console.log('[OpenCode Event]', event.type, JSON.stringify(event).substring(0, 500));
            }

            // 处理工具调用 - OpenCode 实际格式
            // { type: 'tool_use', part: { tool: 'read', callID: '...', state: { status, input, output } } }
            if (event.type && (
              event.type.includes('tool') || 
              event.type.includes('mcp') || 
              event.type.includes('skill') ||
              event.type.includes('function') ||
              event.type.includes('action')
            )) {
              // 检查工具调用次数，防止无限循环
              toolCallCount++;
              console.log(`[OpenCode] Tool call #${toolCallCount}:`, event.type, event.part?.tool || event.part?.name || 'unknown');

              if (toolCallCount > MAX_TOOL_CALLS) {
                console.error(`Too many tool calls (${toolCallCount}), possible infinite loop detected`);
                yield {
                  type: 'error',
                  error: `工具调用次数超过限制 (${MAX_TOOL_CALLS})，可能存在循环调用，已自动终止`
                };
                return;
              }

              // OpenCode 格式: 优先从 part 提取
              const part = event.part;

              // 提取工具信息
              let toolName = 'unknown';
              let toolArgs: any = {};
              let toolResult: any = null;
              let toolStatus: 'pending' | 'executing' | 'completed' | 'failed' = 'executing';
              let toolId = `tool-${Date.now()}`;

              if (part && part.type === 'tool') {
                // OpenCode 实际格式
                toolName = part.tool || part.name || 'unknown';
                toolId = part.callID || part.id || toolId;

                if (part.state) {
                  toolStatus = part.state.status === 'completed' ? 'completed' : 
                               part.state.status === 'failed' ? 'failed' : 'executing';
                  toolArgs = part.state.input || {};
                  toolResult = part.state.output || null;
                }
              } else {
                // 兼容其他格式
                const toolInfo = event.tool_call || event.tool || event.function || event;
                toolName = toolInfo.name || event.name || 'unknown';
                toolArgs = toolInfo.arguments || toolInfo.input || event.arguments || {};
                toolStatus = event.type.includes('result') || event.type.includes('output') ? 'completed' : 'executing';
                toolResult = event.result || event.output || toolInfo.result || null;
                toolId = toolInfo.id || event.id || event.callID || toolId;
              }

              // 解析 arguments 如果是字符串
              if (typeof toolArgs === 'string') {
                try {
                  toolArgs = JSON.parse(toolArgs);
                } catch {
                  toolArgs = { raw: toolArgs };
                }
              }

              const toolCallData = {
                id: toolId,
                name: toolName,
                arguments: toolArgs,
                status: toolStatus
              };

              // 如果有结果，发送 tool_result
              if (toolResult) {
                let parsedResult = toolResult;
                if (typeof toolResult === 'string') {
                  try {
                    parsedResult = JSON.parse(toolResult);
                  } catch {
                    parsedResult = { output: toolResult };
                  }
                }
                yield {
                  type: 'tool_result',
                  toolCall: {
                    ...toolCallData,
                    result: parsedResult,
                    status: 'completed'
                  }
                };
              } else {
                yield {
                  type: 'tool_call',
                  toolCall: toolCallData
                };
              }
            }

            // 处理文件修改事件
            if (event.type === 'file_change' || event.type === 'file_modified' || event.type === 'write' || event.type === 'edit') {
              const fileChange = event.file || event.path || event;
              const filePath = typeof fileChange === 'string' ? fileChange : (fileChange.path || fileChange.name || fileChange.file);

              if (filePath) {
                yield {
                  type: 'tool_call',
                  toolCall: {
                    id: `file-${Date.now()}`,
                    name: 'file_change',
                    arguments: { path: filePath },
                    result: { 
                      path: filePath,
                      action: event.action || 'modified'
                    },
                    status: 'completed'
                  }
                };
              }
            }

          } catch (parseError) {
            console.warn('Failed to parse CLI response line:', line, parseError);
            // 继续处理其他行
          }
        }
      } finally {
        rl.close();
      }

      // 等待进程退出并检查状态
      const exitCode = await exitPromise;

      // 记录 stderr（如果有）
      if (stderr && !stderr.includes('DEBUG') && !stderr.includes('INFO')) {
        console.warn('CLI stderr:', stderr);
      }

      if (exitCode !== 0) {
        throw new Error(`OpenCode CLI exited with code ${exitCode}. Stderr: ${stderr.substring(0, 500)}`);
      }

      yield { type: 'done' };

    } catch (error) {
      console.error('CLI query failed:', error);
      console.error('Temp file path:', tempFile);
      console.error('Temp file exists:', fs.existsSync(tempFile));

      // 记录详细的错误信息
      if (error && typeof error === 'object') {
        const err = error as any;
        if (err.stdout) {
          console.error('CLI stdout (first 1000 chars):', String(err.stdout).substring(0, 1000));
        }
        if (err.stderr) {
          console.error('CLI stderr (first 1000 chars):', String(err.stderr).substring(0, 1000));
        }
        if (err.code !== undefined) {
          console.error('CLI exit code:', err.code);
        }
        if (err.signal) {
          console.error('CLI signal:', err.signal);
        }
      }

      // 尝试读取临时文件内容以进行调试
      try {
        if (fs.existsSync(tempFile)) {
          const fileContent = fs.readFileSync(tempFile, 'utf8');
          console.error('Temporary file content (first 500 chars):', fileContent.substring(0, 500));
        }
      } catch (readError) {
        console.error('Failed to read temp file:', readError);
      }

      // Yield error chunk instead of throwing
      yield {
        type: 'error',
        error: error instanceof Error ? error.message : 'CLI pipe query failed'
      };
      return;
    } finally {
      // 清理临时文件
      if (tempFileCreated) {
        try {
          if (fs.existsSync(tempFile)) {
            this.safeUnlink(tempFile);
            console.log('Cleaned up temporary file:', tempFile);
          }
        } catch (cleanupError) {
          console.warn('Failed to cleanup temporary file:', tempFile, cleanupError);
        }
      }
    }
  }

