        stream: true // 启用流式响应
      };

      console.log('Request data:', JSON.stringify(requestData, null, 2));

      // 写入临时文件
      fs.writeFileSync(tempFile, JSON.stringify(requestData, null, 2));
      tempFileCreated = true;
      console.log('Created temporary request file:', tempFile);

      // 构建命令参数
      const args = this.buildCLIArgs(options);

      // 构建完整的命令：使用重定向将文件内容作为输入
      const opencodeCmd = `"${this.opencodePath}" ${args.join(' ')}`;
      const redirectCmd = `${opencodeCmd} < "${tempFile}"`;

      console.log('Executing redirect command:', redirectCmd);

      // 使用 spawn 执行重定向命令，以支持流式输出
      const child = spawn(redirectCmd, {
        shell: true,
        windowsHide: true,
        stdio: ['pipe', 'pipe', 'pipe']
      });

      // 设置超时
      const timeout = 300000; // 300秒
      const timeoutId = setTimeout(() => {
        try {
          child.kill('SIGTERM');
        } catch (e) {
          console.warn('Failed to kill child process on timeout:', e);
        }
      }, timeout);

      // 收集 stderr 用于错误报告
      let stderr = '';
      child.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      // 创建 readline 接口用于逐行处理 stdout
      const rl = readline.createInterface({
        input: child.stdout,
        crlfDelay: Infinity
      });

      // 创建进程退出 promise
      const exitPromise = new Promise<number | null>((resolve, reject) => {
        child.on('error', reject);

        child.on('close', (code, _signal) => {
          clearTimeout(timeoutId);
          resolve(code);
        });
      });

      // 工具调用计数器和循环保护
      const MAX_TOOL_CALLS = 50; // 最大工具调用次数
      const MAX_STEP_START = 100; // 最大 step_start 事件数
      let toolCallCount = 0;
      let stepStartCount = 0;

      // 实时逐行处理 stdout 流
      try {
        for await (const line of rl) {
          if (!line.trim()) continue;

          try {
            const event = JSON.parse(line.trim());

            // 处理错误事件
            if (event.type === 'error') {
              console.error('CLI error event:', event);
              yield {
                type: 'error',
                error: event.error?.message || event.error || 'CLI error'
              };
              return;
            }

            // 处理思考事件
            if (event.type === 'reasoning' && event.part?.text !== undefined) {
              yield {
                type: 'thinking',
                content: event.part.text
              };
            }

            // 处理文本事件
            if (event.type === 'text' && event.part?.text !== undefined) {
              yield {
                type: 'text',
                content: event.part.text
              };
            }

            // 处理其他文本字段（兼容性）
            if (event.type === 'text' && event.text !== undefined) {
              yield {
                type: 'text',
                content: event.text
              };
            }

            // 处理步骤完成事件（忽略，继续）
            if (event.type === 'step_finish') {
              // 步骤完成，继续等待更多内容
            }

          } catch (parseError) {
            console.warn('Failed to parse CLI response line:', line, parseError);
            // 继续处理其他行
          }
        }
      } finally {
        rl.close();
      }

      // 等待进程退出并检查状态
      const exitCode = await exitPromise;

      // 记录 stderr（如果有）
      if (stderr && !stderr.includes('DEBUG') && !stderr.includes('INFO')) {
        console.warn('CLI stderr:', stderr);
      }

      if (exitCode !== 0) {
        throw new Error(`OpenCode CLI exited with code ${exitCode}. Stderr: ${stderr.substring(0, 500)}`);
      }

      yield { type: 'done' };

    } catch (error) {
      console.error('CLI redirect query failed:', error);
      console.error('Temp file path:', tempFile);
      console.error('Temp file exists:', fs.existsSync(tempFile));

      // 记录详细的错误信息
      if (error && typeof error === 'object') {
        const err = error as any;
        if (err.stdout) {
          console.error('CLI stdout (first 1000 chars):', String(err.stdout).substring(0, 1000));
        }
        if (err.stderr) {
          console.error('CLI stderr (first 1000 chars):', String(err.stderr).substring(0, 1000));
        }
        if (err.code !== undefined) {
          console.error('CLI exit code:', err.code);
        }
        if (err.signal) {
          console.error('CLI signal:', err.signal);
        }
      }

      // 尝试读取临时文件内容以进行调试
      try {
        if (fs.existsSync(tempFile)) {
          const fileContent = fs.readFileSync(tempFile, 'utf8');
          console.error('Temporary file content (first 500 chars):', fileContent.substring(0, 500));
        }
      } catch (readError) {
        console.error('Failed to read temp file:', readError);
      }

      // Yield error chunk instead of throwing
      yield {
        type: 'error',
        error: error instanceof Error ? error.message : 'CLI redirect query failed'
      };
      return;
    } finally {
      // 清理临时文件
      if (tempFileCreated) {
        try {
          if (fs.existsSync(tempFile)) {
            this.safeUnlink(tempFile);
            console.log('Cleaned up temporary file:', tempFile);
          }
        } catch (cleanupError) {
          console.warn('Failed to cleanup temporary file:', tempFile, cleanupError);
        }
      }
    }
  }

  private async *queryViaAPI(
    prompt: string,
    options?: QueryOptions
  ): AsyncGenerator<StreamChunk> {
    const body = this.buildRequestBody(prompt, options);
    const endpoint = this.getAPIEndpoint(options?.model);

    console.log('Sending request to:', endpoint);
    console.log('Model:', body.model);

    const response = await fetch(endpoint, {
      method: 'POST',
      headers: this.getHeaders(options?.model),
      body: JSON.stringify(body),
      signal: this.abortController?.signal
    });

    if (!response.ok) {
      const errorText = await response.text();
      throw new Error(`API error: ${response.status} - ${errorText}`);
    }

    if (body.stream) {
      yield* this.handleStreamingResponse(response);
    } else {
      const data = await response.json();
      yield* this.handleNonStreamingResponse(data);
    }
  }

  stopGeneration(): void {
    if (this.abortController) {
      this.abortController.abort();
      this.abortController = null;
    }
  }

  private buildRequestBody(prompt: string, options?: QueryOptions): any {
    const messages = this.buildMessages(prompt, options);
    const model = options?.model || this.getActiveModel();

    // Extract the model name without provider prefix for API
    const modelName = model.includes('/') ? model.split('/')[1] : model;

    const body: any = {
      model: modelName,
      messages,
      stream: options?.stream !== false,
      temperature: options?.temperature ?? 0.7,
    };

    if (options?.maxTokens) {
      body.max_tokens = options.maxTokens;
    }

    // 添加思考模式参数（Claude 模型）
    if (model.includes('claude') && options?.thinking) {
      body.thinking = {
        type: 'enabled',
        budget_tokens: 16000
      };
    }

    return body;
  }

  private buildMessages(prompt: string, options?: QueryOptions): any[] {
    const messages: any[] = [];

    // 添加系统提示
    if (options?.systemPrompt) {
      messages.push({
        role: 'system',
        content: options.systemPrompt
      });
    }

    // 添加对话历史
    if (options?.conversationHistory) {
      for (const msg of options.conversationHistory) {
        // 检查历史消息是否有附件
        if (msg.images && msg.images.length > 0) {
          // 检查附件是否已保存到文件系统（有 filePath）
          const hasFileAttachments = msg.images.some((att: any) => att.filePath);

          if (hasFileAttachments) {
            // 新格式：附件已保存到文件，文件路径已包含在消息内容中
            // 直接使用消息内容，不添加额外的附件内容
            messages.push({
              role: msg.role,
              content: msg.content
            });
          } else {
            // 旧格式：附件以base64嵌入
            // 构建包含附件的内容数组
            const contentParts: any[] = [];

            // 添加附件
            for (const attachment of msg.images) {
              contentParts.push(...this.buildAttachmentContent(attachment));
            }

            // 添加文本内容（如果有）
            if (msg.content && msg.content.trim()) {
              contentParts.push({
                type: 'text',
                text: msg.content
              });
            }

            messages.push({
              role: msg.role,
              content: contentParts
            });
          }
        } else {
          // 普通文本消息
          messages.push({
            role: msg.role,
            content: msg.content
          });
        }
      }
    }

    // 添加当前提示（可能包含附件）
    const currentAttachments = options?.attachments || [];

    // 检查是否有附件已经保存到文件系统（有 filePath）
    const hasFileAttachments = currentAttachments.some(att => att.filePath);

    if (currentAttachments.length > 0 && !hasFileAttachments) {
      // 旧格式：附件以base64嵌入
      // 构建包含附件的内容数组
      const contentParts: any[] = [];

      // 添加附件
      for (const attachment of currentAttachments) {
        contentParts.push(...this.buildAttachmentContent(attachment));
      }

      // 添加文本内容
      contentParts.push({
        type: 'text',
        text: prompt
      });

      messages.push({
        role: 'user',
        content: contentParts
      });
    } else {
      // 新格式：附件已保存到文件，文件路径已包含在提示中
      // 或者没有附件，普通文本消息
      messages.push({
        role: 'user',
        content: prompt
      });
    }

    return messages;
  }

  private buildAttachmentContent(attachment: ImageAttachment): any[] {
    const contentParts: any[] = [];

    // 文件已保存到仓库的附件目录，通过 filePath 字段访问
    // 用户消息中已包含文件路径信息，这里只需提供简单的引用
    if (attachment.filePath) {
      // 文件已保存到仓库，可以通过 MCP read_file 工具读取
      contentParts.push({
        type: 'text',
        text: `[附件: ${attachment.fileName || '文件'} - 已保存到仓库: ${attachment.filePath}]`
      });
    } else if (attachment.mimeType.startsWith('image/')) {
      // 图片附件（无文件路径的旧格式）
      contentParts.push({
        type: 'image',
        source: {
          type: 'base64',
          media_type: attachment.mimeType,
          data: attachment.base64Data
        }
      });
    } else if (
      attachment.mimeType.includes('text/') ||
      attachment.mimeType.includes('application/json') ||
      attachment.mimeType.includes('application/javascript') ||
      attachment.mimeType.includes('application/xml') ||
      attachment.fileName?.match(/\.(txt|md|json|js|ts|jsx|tsx|py|java|c|cpp|h|cs|html|css|xml|yaml|yml|sql|sh|bash)$/i)
    ) {
      // 文本文件（无文件路径的旧格式）：尝试解码base64数据
      try {
        let textContent: string;
        try {
          textContent = Buffer.from(attachment.base64Data, 'base64').toString('utf-8');
        } catch {
          textContent = (globalThis as any).atob?.(attachment.base64Data) || `[无法解码base64内容]`;
        }

        contentParts.push({
          type: 'text',
          text: `[文件: ${attachment.fileName || 'attachment'}]\n\n${textContent}`
        });
      } catch (error) {
        console.warn('Failed to decode text attachment:', error);
        contentParts.push({
          type: 'text',
          text: `[文件: ${attachment.fileName || 'attachment'} (文本文件，解码失败)]`
        });
      }
    } else if (
      attachment.mimeType.includes('application/pdf') ||
      attachment.fileName?.match(/\.(pdf|doc|docx|xls|xlsx|ppt|pptx)$/i)
    ) {
      // PDF或Office文档：提供文件信息但不包含内容
      contentParts.push({
        type: 'text',
        text: `[文件: ${attachment.fileName || 'attachment'} (${attachment.mimeType}) - 由于格式限制，无法提取文本内容]`
      });
    } else {
      // 其他二进制文件
      contentParts.push({
        type: 'text',
        text: `[文件: ${attachment.fileName || 'attachment'} (${attachment.mimeType}) - 二进制文件]`
      });
    }

    return contentParts;
  }

  private getAPIEndpoint(modelId?: string): string {
    const model = modelId || this.getActiveModel();

    // 本地模型
    if (this.plugin.settings.localModel.enabled || model.startsWith('local/')) {
      const baseUrl = this.plugin.settings.localModel.baseUrl.replace(/\/$/, '');
      return `${baseUrl}/v1/chat/completions`;
    }

    // OpenCode Zen 模型
    if (model.startsWith('opencode/')) {
      return getModelEndpoint(model);
    }

    // 使用配置的 provider
    if (this.activeProvider?.baseURL) {
      return `${this.activeProvider.baseURL}/chat/completions`;
    }

    // 默认使用 OpenCode Zen
    return 'https://opencode.ai/zen/v1/chat/completions';
  }

  private getHeaders(modelId?: string): Record<string, string> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    const model = modelId || this.getActiveModel();

    // 本地模型不需要认证
    if (this.plugin.settings.localModel.enabled || model.startsWith('local/')) {
      return headers;
    }

    // OpenCode Zen 模型
    if (model.startsWith('opencode/')) {
      const apiKey = this.plugin.settings.opencodeZenApiKey 
        || this.opencodeAuth?.['opencode']?.apiKey;
      if (apiKey) {
        headers['Authorization'] = `Bearer ${apiKey}`;
      }
      return headers;
    }

    // 其他提供商
    if (this.activeProvider?.apiKey) {
      headers['Authorization'] = `Bearer ${this.activeProvider.apiKey}`;
    }

    return headers;
  }

  private async *handleStreamingResponse(response: Response): AsyncGenerator<StreamChunk> {
    const reader = response.body?.getReader();
    if (!reader) {
      yield { type: 'error', error: 'No response body' };
      return;
    }

    const decoder = new TextDecoder();
    let buffer = '';

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        for (const line of lines) {
          if (line.trim() === '' || !line.startsWith('data: ')) continue;

          const data = line.slice(6);
          if (data === '[DONE]') {
            yield { type: 'done' };
            return;
          }

          try {
            const parsed = JSON.parse(data);
            const delta = parsed.choices?.[0]?.delta;

            // 处理思考过程
            if (delta?.thinking) {
              yield {
                type: 'thinking',
                content: delta.thinking
              };
            }

            if (delta?.content) {
              yield {
                type: 'text',
                content: delta.content
              };
            }
          } catch {
            // 忽略解析错误
          }
        }
      }
    } finally {
      reader.releaseLock();
    }

    yield { type: 'done' };
  }

  private async *handleNonStreamingResponse(data: any): AsyncGenerator<StreamChunk> {
    const content = data.choices?.[0]?.message?.content || '';

    yield {
      type: 'text',
      content
    };

    yield { type: 'done' };
  }

  // OpenCode Session Sync Methods

  async syncDeleteSession(sessionId: string): Promise<boolean> {
    if (!this.plugin.settings.syncWithOpenCode) {
      return true;
    }

    // Method 1: Try using CLI
    if (this.opencodePath) {
      try {
        await execAsync(`"${this.opencodePath}" session delete ${sessionId}`);
        console.log(`Deleted session ${sessionId} via CLI`);
        return true;
      } catch (error) {
        console.warn('Failed to delete session via CLI:', error);
      }
    }

    // Method 2: Try deleting session file directly
    const sessionsPath = this.getSessionsPath();
    if (sessionsPath) {
      try {
        const sessionFile = path.join(sessionsPath, `${sessionId}.json`);
        if (fs.existsSync(sessionFile)) {
          fs.unlinkSync(sessionFile);
          console.log(`Deleted session file ${sessionFile}`);
          return true;
        }
      } catch (error) {
        console.warn('Failed to delete session file:', error);
      }
    }

    return false;
  }

  async listOpenCodeSessions(): Promise<string[]> {
    // Method 1: Try using CLI
    if (this.opencodePath) {
      try {
        const { stdout } = await execAsync(`"${this.opencodePath}" session list --format json`);
        const sessions = JSON.parse(stdout);
        return sessions.map((s: any) => s.id);
      } catch {
        // Fall through to file method
      }
    }

    // Method 2: Read session files directly
    const sessionsPath = this.getSessionsPath();
    if (sessionsPath && fs.existsSync(sessionsPath)) {
      try {
        const files = fs.readdirSync(sessionsPath);
        return files
          .filter(f => f.endsWith('.json'))
          .map(f => f.replace('.json', ''));
      } catch {
        return [];
      }
    }

    return [];
  }

  async getOpenCodeSession(sessionId: string): Promise<OpenCodeSession | null> {
    const sessionsPath = this.getSessionsPath();
    if (!sessionsPath) return null;

    try {
      const sessionFile = path.join(sessionsPath, `${sessionId}.json`);
      if (fs.existsSync(sessionFile)) {
        const content = fs.readFileSync(sessionFile, 'utf-8');
        return JSON.parse(content);
      }
    } catch {
      return null;
    }

    return null;
  }

  getConfig(): OpenCodeConfig | null {
    return this.opencodeConfig;
  }

  getAuth(): OpenCodeAuth | null {
    return this.opencodeAuth;
  }

  setSessionId(sessionId: string | null): void {
    this.currentSessionId = sessionId;
  }

  getSessionId(): string | null {
    return this.currentSessionId;
  }

  getOpenCodePath(): string | null {
    return this.opencodePath;
  }

  /**
   * Load available MCP servers from opencode CLI
   */
  private async loadAvailableMCPServers(): Promise<void> {
    const servers: Array<{name: string; description?: string; enabled: boolean}> = [];

    // 1) Load from config if available
    const configAny = this.opencodeConfig as any;
    const mcpConfig = configAny?.mcp || configAny?.mcpServers || configAny?.mcp_servers || configAny?.mcps;
    if (mcpConfig) {
      if (Array.isArray(mcpConfig)) {
        for (const item of mcpConfig) {
          if (item && item.name) {
            servers.push({
              name: String(item.name),
              description: item.description,
              enabled: item.enabled !== false
            });
          }
        }
      } else {
        for (const [name, config] of Object.entries(mcpConfig)) {
          const desc = (config as any)?.type === 'remote'
            ? ((config as any)?.url || 'Remote MCP server')
            : ((config as any)?.command?.join(' ') || 'Local MCP server');
          servers.push({
            name,
            description: desc,
            enabled: (config as any)?.enabled !== false
          });
        }
      }
    }

    if (this.opencodePath) {
      try {
        // Try different command formats for Windows and Unix
        const isWindows = process.platform === 'win32';
        let stdout = '';

      const commands = isWindows ? [
        `"${this.opencodePath}" mcp list --format json 2>NUL`,
        `"${this.opencodePath}" mcp list 2>NUL`,
        `"${this.opencodePath}" mcp ls 2>NUL`,
        `"${this.opencodePath}" mcps list 2>NUL`
      ] : [
        `"${this.opencodePath}" mcp list --format json 2>/dev/null`,
        `"${this.opencodePath}" mcp list 2>/dev/null`,
        `"${this.opencodePath}" mcp ls 2>/dev/null`,
        `"${this.opencodePath}" mcps list 2>/dev/null`
      ];

        console.log('[OpenCode] Trying MCP commands:', commands);

        for (const cmd of commands) {
          try {
            console.log('[OpenCode] Executing MCP command:', cmd);
            const result = await execAsync(cmd, { 
              maxBuffer: 10 * 1024 * 1024,
              timeout: this.plugin.settings.cliTimeout || 300000,
              cwd: this.getCliCwd(),
            });
            stdout = result.stdout || result.stderr || '';
            console.log('[OpenCode] Successfully executed MCP command');
            if (stdout.trim()) break;
          } catch (error) {
            console.warn('[OpenCode] MCP command failed:', cmd, error);
            continue;
          }
        }

        // Try to parse as JSON first
        try {
          const parsed = JSON.parse(stdout);
          if (Array.isArray(parsed)) {
            const cliServers = parsed.map((s: any) => ({
              name: this.cleanCliText(s.name || s.id || ''),
              description: this.cleanCliText(s.description || s.name || ''),
              enabled: s.enabled !== false
            }));
            for (const s of cliServers) {
              if (!servers.find(existing => existing.name === s.name)) {
                servers.push(s);
              }
            }
            console.log(`[OpenCode] Loaded ${cliServers.length} MCP servers from CLI`);
          }
        } catch {
          // Parse text output
          const lines = stdout.trim().split('\n');
          const cliServers: Array<{name: string; description?: string; enabled: boolean}> = [];
          for (const line of lines) {
            const parsedLine = this.parseToolListLineV2(line);
            if (parsedLine) {
              cliServers.push({
                name: parsedLine.name,
                description: parsedLine.description || parsedLine.name,
                enabled: true
              });
            }
          }
          for (const s of cliServers) {
            if (!servers.find(existing => existing.name === s.name)) {
              servers.push(s);
            }
          }
          if (cliServers.length > 0) {
            console.log(`[OpenCode] Loaded ${cliServers.length} MCP servers from text output`);
          }
        }

      } catch (error) {
        console.warn('[OpenCode] Failed to load MCP servers from CLI:', error);
      }
    }

    if (servers.length === 0) {
      console.log('No MCP servers detected, using default MCP servers');
      servers.push(...this.getDefaultMCPServers());
    }

    this.availableMCPServers = servers;
  }

  /**
   * Get default MCP servers
   */
  private getDefaultMCPServers(): Array<{name: string; description?: string; enabled: boolean}> {
    return [
      {
        name: 'obsidian-vault',
        description: 'Obsidian Vault Operations (read/write notes)',
        enabled: true
      }
    ];
  }

  /**
   * Load available skills from opencode CLI
   */
  private async loadAvailableSkills(): Promise<void> {
    const skills: Array<{name: string; description?: string; enabled: boolean}> = [];

    // 1) Load from config if available (skills/tools)
    const configAny = this.opencodeConfig as any;
    if (configAny?.skills) {
      if (Array.isArray(configAny.skills)) {
        for (const item of configAny.skills) {
          if (typeof item === 'string' && item) {
            skills.push({ name: item, description: 'Configured skill', enabled: true });
          } else if (item && typeof item === 'object' && item.name) {
            skills.push({ name: String(item.name), description: item.description, enabled: item.enabled !== false });
          }
        }
      } else {
        const configSkills = Object.keys(configAny.skills);
        for (const name of configSkills) {
          if (name) {
            skills.push({ name, description: 'Configured skill', enabled: true });
          }
        }
      }
    }
    if (this.opencodeConfig?.tools) {
      for (const [name, enabled] of Object.entries(this.opencodeConfig.tools)) {
        if (enabled && !skills.find(s => s.name === name)) {
          skills.push({ name, description: 'Configured tool', enabled: true });
        }
      }
    }

    // 1.5) Load skills from skills directory if configured or default locations
    const skillsDirs: string[] = [];
    const configSkillsDir = configAny?.skills_dir || configAny?.skillsDir;
    if (typeof configSkillsDir === 'string') {
      skillsDirs.push(configSkillsDir);
    }

    const vaultPath = this.plugin.getVaultPath();
    if (vaultPath) {
      skillsDirs.push(
        path.join(vaultPath, '.opencode', 'skills'),
        path.join(vaultPath, '.claude', 'skills'),
        path.join(vaultPath, '.agents', 'skills')
      );
    }

    const homeDir = process.env.HOME || process.env.USERPROFILE;
    const appData = process.env.APPDATA;
    const localAppData = process.env.LOCALAPPDATA;
    if (homeDir) {
      skillsDirs.push(
        path.join(homeDir, '.config', 'opencode', 'skills'),
        path.join(homeDir, '.config', 'claude', 'skills'),
        path.join(homeDir, '.config', 'agents', 'skills')
      );
    }
    if (appData) {
      skillsDirs.push(path.join(appData, 'opencode', 'skills'));
    }
    if (localAppData) {
      skillsDirs.push(path.join(localAppData, 'opencode', 'skills'));
    }

    for (const skillsDir of skillsDirs) {
      if (!skillsDir || !fs.existsSync(skillsDir)) continue;
      try {
        const entries = fs.readdirSync(skillsDir, { withFileTypes: true });
        for (const entry of entries) {
          if (!entry.isDirectory()) continue;
          const skillName = entry.name;
          if (!skills.find(s => s.name === skillName)) {
            skills.push({ name: skillName, description: 'Local skill', enabled: true });
          }
        }
      } catch (error) {
        console.warn('[OpenCode] Failed to read skills directory:', skillsDir, error);
      }
    }

    if (this.opencodePath) {
      try {
        // Try different command formats
      const commands = [
        `"${this.opencodePath}" skills list --format json`,
        `"${this.opencodePath}" skills --format json`,
        `"${this.opencodePath}" skills list`,
        `"${this.opencodePath}" skills`,
        `"${this.opencodePath}" skill list`,
        `"${this.opencodePath}" skill ls`
      ];

        console.log('[OpenCode] Trying skills commands:', commands);
        let stdout = '';

        for (const cmd of commands) {
          try {
            console.log('[OpenCode] Executing skills command:', cmd);
            const result = await execAsync(cmd, { 
              maxBuffer: 10 * 1024 * 1024,
              timeout: this.plugin.settings.cliTimeout || 300000,
              cwd: this.getCliCwd(),
            });
            stdout = result.stdout || result.stderr || '';
            console.log('[OpenCode] Successfully executed skills command');
            console.log('[OpenCode] Raw output (first 200 chars):', stdout.substring(0, 200));
            if (stdout.trim()) break;
          } catch (error) {
            console.warn('[OpenCode] Skills command failed:', cmd, error);
            continue;
          }
        }

        // Try to parse as JSON first
        try {
          const skillsData = JSON.parse(stdout);
          if (Array.isArray(skillsData)) {
            const cliSkills = skillsData.map((s: any) => ({
              name: this.cleanCliText(s.name || s.id || ''),
              description: this.cleanCliText(s.description || s.name || ''),
              enabled: s.enabled !== false
            }));
            for (const s of cliSkills) {
              if (!skills.find(existing => existing.name === s.name)) {
                skills.push(s);
              }
            }
            console.log(`[OpenCode] Loaded ${cliSkills.length} skills from CLI`);
          } else {
            console.warn('[OpenCode] Skills data is not an array:', typeof skillsData);
          }
        } catch {
          // Parse text output
          const lines = stdout.trim().split('\n');
          const cliSkills: Array<{name: string; description?: string; enabled: boolean}> = [];
          for (const line of lines) {
            const parsedLine = this.parseToolListLineV2(line);
            if (parsedLine) {
              cliSkills.push({
                name: parsedLine.name,
                description: parsedLine.description || parsedLine.name,
                enabled: true
              });
            }
          }
          for (const s of cliSkills) {
            if (!skills.find(existing => existing.name === s.name)) {
              skills.push(s);
            }
          }
          if (cliSkills.length > 0) {
            console.log(`[OpenCode] Loaded ${cliSkills.length} skills from text output`);
          }
        }

      } catch (error) {
        console.warn('[OpenCode] Failed to load skills from CLI:', error);
      }
    }

    this.availableSkills = skills;
  }

  private cleanCliText(value: string): string {
    return value
      .replace(/\x1b\[[0-9;]*[a-zA-Z]/g, '')
      .replace(/\r/g, '')
      .trim();
  }

  private parseToolListLine(line: string): {name: string; description?: string} | null {
    if (!line) return null;
    const clean = this.cleanCliText(line);
    if (!clean) return null;
    if (clean.includes('DEBUG') || clean.includes('INFO') || clean.includes('Error:')) {
      return null;
    }
    if (/^(mcps?|skills?)$/i.test(clean.trim())) return null;
    if (/^search$/i.test(clean.trim())) return null;
    if (/^[┌┬├┼└┴─│\s]+$/.test(clean)) return null;
    const trimmed = clean.replace(/^[┌┬├┼└┴─│\s]+/, '').trim();

    if (trimmed.includes('|')) {
      const normalized = trimmed;
      const parts = normalized.split('|').map(p => p.trim()).filter(Boolean);
      if (parts.length > 0) {
        const name = parts[0];
        const description = parts[1];
        if (name && this.isLikelyToolName(name)) return { name, description };
      }
    }
    const match = trimmed.match(/^([A-Za-z0-9._/-]+)\s+(?:.+)?/);
    if (match) {
      if (!this.isLikelyToolName(match[1])) return null;
      return { name: match[1] };
    }
    return null;
  }

  private parseToolListLineV2(line: string): {name: string; description?: string} | null {
    if (!line) return null;
    const clean = this.cleanCliText(line);
    const trimmedClean = clean.trim();
    if (!trimmedClean) return null;
    if (trimmedClean.includes('DEBUG') || trimmedClean.includes('INFO') || trimmedClean.includes('Error:')) {
      return null;
    }
    if (/^(mcps?|skills?)$/i.test(trimmedClean)) return null;
    if (/^search$/i.test(trimmedClean)) return null;
    if (/^(name|type|status|enabled|tools?|tool)$/i.test(trimmedClean)) return null;
    if (/^[-=]{3,}$/.test(trimmedClean)) return null;
    if (/^[\s┌┐└┘├┤┬┴┼─│═╔╗╚╝╠╣╦╩╬]+$/.test(trimmedClean)) return null;

    const normalized = trimmedClean.replace(/[│║]/g, '|');
    if (normalized.includes('|')) {
      const parts = normalized.split('|').map(p => p.trim()).filter(Boolean);
      if (parts.length > 0) {
        const name = parts[0];
        const description = parts.slice(1).join(' ').trim() || undefined;
        if (name && this.isLikelyToolName(name)) return { name, description };
      }
    }

    const stripped = normalized.replace(/^[✓✔✗✘•*-]+\s*/u, '');
    const match = stripped.match(/^([A-Za-z0-9._:@/+()-]+)\s*(.*)?$/);
    if (match) {
      if (!this.isLikelyToolName(match[1])) return null;
      const description = match[2]?.trim() || undefined;
      return { name: match[1], description };
    }
    return null;
  }

  private isLikelyToolName(name: string): boolean {
    const trimmed = name.trim();
    if (!trimmed) return false;
    if (trimmed.length <= 1) return false;
    const lower = trimmed.toLowerCase();
    if (['name', 'type', 'status', 'enabled', 'tools', 'tool'].includes(lower)) return false;
    if (/^[-─]+$/.test(trimmed)) return false;
    return true;
  }

  private getCliCwd(): string {
    const vaultPath = this.plugin.getVaultPath();
    if (vaultPath && fs.existsSync(vaultPath)) {
      return vaultPath;
    }
    const homeDir = process.env.HOME || process.env.USERPROFILE;
    if (homeDir && fs.existsSync(homeDir)) {
      return homeDir;
    }
    return process.cwd();
  }
