  }", "new_string": "  public async findOpenCodePath(): Promise<void> {
    // 首先重置路径
    this.opencodePath = null;

    // 1. 优先使用配置的路径（如果配置了且有效）
    if (this.plugin.settings.opencodePath && this.plugin.settings.opencodePath.trim()) {
      const configuredPath = this.plugin.settings.opencodePath.replace(/\r/g, '').trim();

      // 验证并规范化路径
      let validPath = this.validateAndNormalizePath(configuredPath);
      if (validPath) {
        this.opencodePath = validPath;
        console.log('Using configured opencode path:', validPath);
        return;
      } else {
        console.warn('Configured opencode path is invalid or does not exist:', configuredPath);
      }
    }

    // 2. 在系统PATH中查找
    console.log('Searching for opencode in system PATH...');
    const pathFound = await this.findOpenCodeInPath();
    if (pathFound) {
      this.opencodePath = pathFound;
      console.log('Found opencode via PATH:', pathFound);
      return;
    }

    // 3. 检查常见安装位置
    console.log('Checking common installation locations...');
    const commonFound = this.findOpenCodeInCommonLocations();
    if (commonFound) {
      this.opencodePath = commonFound;
      console.log('Found opencode in common location:', commonFound);
      return;
    }

    console.warn('Could not find opencode in any location. Please configure the path manually.');
  }

  /**
   * 在系统PATH中查找opencode
   */
  private async findOpenCodeInPath(): Promise<string | null> {
    try {
      const cmd = process.platform === 'win32' ? 'where opencode' : 'which opencode';
      console.log('Executing PATH search command:', cmd);

      const { stdout, stderr } = await execAsync(cmd, { timeout: 10000 });

      if (stderr && stderr.trim()) {
        console.warn('PATH search stderr:', stderr.substring(0, 200));
      }

      if (!stdout || !stdout.trim()) {
        console.log('No opencode found in PATH');
        return null;
      }

      // 处理多个可能的路径
      const paths = stdout.trim().split(/\r?\n/).filter(p => p.trim());
      console.log(`Found ${paths.length} potential opencode paths in PATH`);

      for (const rawPath of paths) {
        const cleanedPath = this.cleanPath(rawPath);
        if (!cleanedPath) continue;

        const validatedPath = this.validateAndNormalizePath(cleanedPath);
        if (validatedPath) {
          console.log('Valid opencode found in PATH:', validatedPath);
          return validatedPath;
        }
      }

      console.log('No valid opencode found in PATH after checking', paths.length, 'paths');
      return null;

    } catch (error) {
      console.warn('Error searching for opencode in PATH:', error);
      return null;
    }
  }

  /**
   * 在常见安装位置查找opencode
   */
  private findOpenCodeInCommonLocations(): string | null {
    const possiblePaths: string[] = [];
    const appData = process.env.APPDATA;
    const localAppData = process.env.LOCALAPPDATA;
    const programFiles = process.env.ProgramFiles;
    const programFilesX86 = process.env['ProgramFiles(x86)'];
    const userProfile = process.env.USERPROFILE;
    const homeDir = process.env.HOME || userProfile;

    if (process.platform === 'win32') {
      // Windows常见安装位置

      // npm全局安装位置
      if (appData) {
        possiblePaths.push(
          path.join(appData, 'npm', 'opencode.cmd'),
          path.join(appData, 'npm', 'opencode'),
          path.join(appData, 'npm', 'opencode.bat')
        );
      }

      // 用户本地安装位置
      if (localAppData) {
        possiblePaths.push(
          path.join(localAppData, 'npm', 'opencode.cmd'),
          path.join(localAppData, 'npm', 'opencode'),
          path.join(localAppData, 'Programs', 'nodejs', 'opencode.cmd'),
          path.join(localAppData, 'Programs', 'nodejs', 'opencode'),
          path.join(localAppData, 'opencode', 'opencode.exe'),
          path.join(localAppData, 'opencode', 'opencode')
        );
      }

      // 程序文件目录
      if (programFiles) {
        possiblePaths.push(
          path.join(programFiles, 'nodejs', 'opencode.cmd'),
          path.join(programFiles, 'nodejs', 'opencode'),
          path.join(programFiles, 'opencode', 'opencode.exe'),
          path.join(programFiles, 'opencode', 'opencode')
        );
      }

      if (programFilesX86) {
        possiblePaths.push(
          path.join(programFilesX86, 'nodejs', 'opencode.cmd'),
          path.join(programFilesX86, 'nodejs', 'opencode'),
          path.join(programFilesX86, 'opencode', 'opencode.exe'),
          path.join(programFilesX86, 'opencode', 'opencode')
        );
      }

      // 用户主目录
      if (userProfile) {
        possiblePaths.push(
          path.join(userProfile, '.opencode', 'opencode.exe'),
          path.join(userProfile, '.opencode', 'opencode'),
          path.join(userProfile, 'AppData', 'Roaming', 'npm', 'opencode.cmd'),
          path.join(userProfile, 'AppData', 'Roaming', 'npm', 'opencode')
        );
      }

    } else {
      // Unix/Linux/Mac常见位置
      possiblePaths.push(
        '/usr/local/bin/opencode',
        '/usr/bin/opencode',
        '/opt/homebrew/bin/opencode',
        '/home/linuxbrew/.linuxbrew/bin/opencode'
      );

      if (homeDir) {
        possiblePaths.push(
          path.join(homeDir, '.local/bin/opencode'),
          path.join(homeDir, '.cargo/bin/opencode'),
          path.join(homeDir, '.nvm/versions/node/*/bin/opencode')
        );
      }
    }

    // 当前目录和node_modules
    possiblePaths.push(
      path.join(process.cwd(), 'opencode'),
      path.join(process.cwd(), 'opencode.cmd'),
      path.join(process.cwd(), 'opencode.exe'),
      path.join(process.cwd(), 'node_modules', '.bin', 'opencode'),
      path.join(process.cwd(), 'node_modules', '.bin', 'opencode.cmd')
    );

    console.log(`Checking ${possiblePaths.length} common locations...`);

    for (const p of possiblePaths) {
      try {
        // 处理通配符路径
        let checkPath = p;
        if (p.includes('*')) {
          const dir = path.dirname(p);
          const pattern = path.basename(p).replace('*', '');

          if (fs.existsSync(dir)) {
            const files = fs.readdirSync(dir);
            const matches = files.filter(f => f.includes(pattern));
            if (matches.length > 0) {
              checkPath = path.join(dir, matches[0]);
            } else {
              continue;
            }
          } else {
            continue;
          }
        }

        const validatedPath = this.validateAndNormalizePath(checkPath);
        if (validatedPath) {
          console.log('Found valid opencode at common location:', validatedPath);
          return validatedPath;
        }
      } catch (err) {
        // 忽略单个路径的错误，继续检查下一个
        continue;
      }
    }

    return null;
  }

  /**
   * 清理路径字符串
   */
  private cleanPath(rawPath: string): string | null {
    if (!rawPath || !rawPath.trim()) {
      return null;
    }

    // 移除引号和多余空格
    let cleaned = rawPath.replace(/["'\r\n]+/g, '').trim();

    // 移除可能的重复路径段（处理像 "H:\node-v22.20.0-win-x64\node-v22.20.0-win-x64\opencode" 这样的问题）
    if (process.platform === 'win32') {
      // 规范化路径分隔符
      cleaned = cleaned.replace(/\//g, '\\');

      // 检查并修复重复的路径段
      const parts = cleaned.split('\\').filter(part => part.trim());
      const uniqueParts: string[] = [];

      for (let i = 0; i < parts.length; i++) {
        if (i === 0 || parts[i] !== parts[i - 1]) {
          uniqueParts.push(parts[i]);
        }
      }

      cleaned = uniqueParts.join('\\');
    }

    return cleaned;
  }

  /**
   * 验证并规范化路径
   */
  private validateAndNormalizePath(possiblePath: string): string | null {
    if (!possiblePath || !possiblePath.trim()) {
      return null;
    }

    try {
      // 检查路径是否存在
      if (!fs.existsSync(possiblePath)) {
        return null;
      }

      // 获取真实路径（解析符号链接、规范化等）
      const realPath = fs.realpathSync(possiblePath);

      // 检查文件是否可执行（或Windows上的批处理文件）
      const stat = fs.statSync(realPath);
      if (!stat.isFile()) {
        return null;
      }

      // 在Windows上，检查是否为可执行文件扩展名
      if (process.platform === 'win32') {
        const ext = path.extname(realPath).toLowerCase();
        if (!['.exe', '.cmd', '.bat', '.ps1', ''].includes(ext)) {
          console.warn('Invalid file extension for opencode on Windows:', ext, realPath);
          return null;
        }
      }

      return realPath;

    } catch (error) {
      console.warn('Error validating path:', possiblePath, error);
      return null;
    }
  }"}
